#include <stdio.h>

int main(){
    int T; if(scanf("%d",&T)!=1) return 0;
    while(T--){
        int num1,num2; char op;
        if(scanf("%d %d %c",&num1,&num2,&op)!=3) break;
        // Skip any whitespace before the operator
        while(op==' '||op=='\n'||op=='\t') if(scanf("%c",&op)!=1) break;
        switch(op){
            case '+': printf("%d\n",num1+num2); break;
            case '-': printf("%d\n",num1-num2); break;
            case '*': printf("%d\n",num1*num2); break;
            case '/': if(num2 != 0) printf("%d\n",num1/num2); else printf("Invalid operator\n"); break;
            default: printf("Invalid operator\n");
        }
    }
    return 0;
}

