import sys

def main():
    data=sys.stdin.read().strip().splitlines()
    if not data:
        return
    T=int(data[0])
    out=[]
    for i in range(1,T+1):
        parts=data[i].split()
        num1=int(parts[0])
        num2=int(parts[1])
        op=parts[2]
        if op=='+':
            out.append(str(num1+num2))
        elif op=='-':
            out.append(str(num1-num2))
        elif op=='*':
            out.append(str(num1*num2))
        elif op=='/':
            if num2 != 0:
                out.append(str(num1//num2))
            else:
                out.append('Invalid operator')
        else:
            out.append('Invalid operator')
    sys.stdout.write('\n'.join(out))

if __name__=='__main__':
    main()

